import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

// Định nghĩa enum cho tất cả các bộ phận cơ thể, làm tiêu chuẩn thống nhất
const BodyPartsEnum = z.enum([
  'Tóc',
  'Ngực',
  'Núm_vú',
  'Âm_hộ',
  'Âm_vật',
  'Chân',
  'Hậu_môn',
  'Bàn_chân',
  'Khác',
]);

// Định nghĩa cấu trúc của một bộ phận cơ thể đơn lẻ, bao gồm cấp độ và kinh nghiệm
const BodyPartSchema = z.object({
    Cấp_độ_nhạy_cảm: z.coerce.number().transform(v => _.clamp(Math.round(v), 1, 4)).describe('Cấp độ nhạy cảm, phạm vi 1-4').prefault(1),
    Kinh_nghiệm: z.coerce.number().transform(v => Math.max(0, v)).describe('Giá trị kinh nghiệm nhận được của bộ phận này').prefault(0),
}).prefault({ Cấp_độ_nhạy_cảm: 1, Kinh_nghiệm: 0 });

// Tạo một bộ dữ liệu bộ phận cơ thể mặc định cho nhân vật mới
const DefaultBodyParts = _.fromPairs(BodyPartsEnum.options.map(part => [part, { Cấp_độ_nhạy_cảm: 1, Kinh_nghiệm: 0 }]));

// Định nghĩa enum cho các bộ phận quần áo
const ClothingPartsEnum = z.enum(['Áo', 'Váy', 'Áo_lót', 'Quần_lót']);

// Tạo một bộ trạng thái quần áo nguyên vẹn mặc định cho trò chơi mới
const DefaultClothingStatus = _.fromPairs(ClothingPartsEnum.options.map(part => [part, 'Hoàn hảo']));

export const Schema = z.object({
  // Phần 1: Biến tạm thời của hành vi biến thái hiện tại, đặt lại mỗi khi bắt đầu trò chơi
  Kẻ_biến_thái_hiện_tại: z.object({
    Bối_cảnh: z.string().describe('Tên bối cảnh xảy ra hành vi biến thái hiện tại').prefault('Không'),
    Nhân_vật_mục_tiêu: z.string().describe('Tên nhân vật mục tiêu của hành vi biến thái hiện tại').prefault('Không'),
    Thời_gian_còn_lại: z.coerce.number().describe('Đơn vị: phút, đếm ngược của hành vi biến thái lần này').prefault(90),
    Số_lượt: z.coerce.number().transform(v => Math.max(0, Math.round(v))).describe('Số lượt đã thực hiện của hành vi biến thái hiện tại').prefault(0),
    Trạng_thái: z.enum(['Đang_diễn_ra', 'Đã_kết_thúc']).describe('Trạng thái của hành vi biến thái hiện tại').prefault('Đang_diễn_ra'),
    Độ_nhẫn_nhịn: z.coerce.number().transform(v => _.clamp(v, 0, 100)).describe('Độ nhẫn nhịn của mục tiêu, giảm dần từ 100').prefault(100),
    Độ_phát_tình: z.coerce.number().transform(v => _.clamp(v, 0, 100)).describe('Độ phát tình của mục tiêu, tăng dần từ 0').prefault(0),
    Độ_cảnh_giác: z.coerce.number().transform(v => _.clamp(v, 0, 100)).describe('Độ cảnh giác của bối cảnh, tăng dần từ 0').prefault(0),
    Số_lần_lên_đỉnh: z.coerce.number().transform(v => Math.max(0, Math.round(v))).describe('Số lần lên đỉnh của mục tiêu trong hành vi lần này').prefault(0),
    Số_lượt_lên_đỉnh_còn_lại: z.coerce.number().transform(v => Math.max(0, Math.round(v))).describe('Số lượt còn lại của trạng thái lên đỉnh').prefault(0),
    Giai_đoạn_hành_vi: z.coerce.number().transform(v => _.clamp(Math.round(v), 1, 4)).describe('Giai đoạn hành vi hiện tại, phạm vi 1-4').prefault(1),
    Tag_duy_trì: z.array(z.string()).describe('Danh sách Tag duy trì của bối cảnh hiện tại').prefault([]),
    Tag_tạm_thời: z.record(z.string().describe('Tên Tag'), z.coerce.number().describe('Số lượt còn lại')).describe('Các Tag tạm thời đang có hiệu lực và số lượt còn lại').prefault({}),
    Tag_nhân_vật: z.array(z.string()).describe('Danh sách Tag nhân vật thường trú của mục tiêu hiện tại').prefault([]),
    Trạng_thái_quần_áo: z.record(ClothingPartsEnum, z.string().describe('Mô tả trạng thái cụ thể của quần áo')).describe('Trạng thái quần áo chính trên người mục tiêu').prefault(DefaultClothingStatus),
  }).prefault({
      Bối_cảnh: 'Không',
      Nhân_vật_mục_tiêu: 'Không',
      Thời_gian_còn_lại: 90,
      Số_lượt: 0,
      Trạng_thái: 'Đang_diễn_ra',
      Độ_nhẫn_nhịn: 100,
      Độ_phát_tình: 0,
      Độ_cảnh_giác: 0,
      Số_lần_lên_đỉnh: 0,
      Số_lượt_lên_đỉnh_còn_lại: 0,
      Giai_đoạn_hành_vi: 1,
      Tag_duy_trì: [],
      Tag_tạm_thời: {},
      Tag_nhân_vật: [],
      Trạng_thái_quần_áo: DefaultClothingStatus
  }),

  // Phần 2: Dữ liệu tăng trưởng vĩnh viễn của tất cả nhân vật, sẽ luôn được giữ lại
  Dữ_liệu_nhân_vật: z.record(
    z.string().describe('Tên nhân vật, ví dụ Thủy Đăng Tâm hoặc Thương Dã Nguyệt'),
    z.object({
      Bộ_phận: z.record(
        BodyPartsEnum,
        BodyPartSchema
      ).describe('Dữ liệu nhạy cảm và kinh nghiệm của tất cả bộ phận cơ thể của nhân vật đó').prefault(DefaultBodyParts),
    }).prefault({ Bộ_phận: DefaultBodyParts })
  ).describe('Một "kho lưu trữ", chứa dữ liệu vĩnh viễn của tất cả nhân vật').prefault({}),
});

$(() => {
  registerMvuSchema(Schema);
})

