    /* Mô tả bầu không khí động */
    const atmospherePool = {
        'Tàu_điện': ["Không khí ngột ngạt, lẫn lộn mùi bữa sáng, nhiều loại nước hoa và mùi ẩm ướt của quần áo chưa khô. Không ai trò chuyện, đa số đeo tai nghe hoặc nhìn điện thoại.", "Dòng người chen chúc như cá mòi đóng hộp khiến cơ thể dán chặt vào nhau, mỗi lần xe rung lắc đều mang lại sự cọ xát và tiếp xúc cơ thể không thể tránh khỏi.", "Kính cửa sổ đọng một lớp sương mờ, cao ốc bên ngoài lùi lại phía sau. Bên tai là tiếng gầm rú của đoàn tàu và tiếng thông báo ga, che lấp mọi âm thanh nhỏ nhất."],
