        'Rạp_chiếu_phim': ["Ánh sáng duy nhất trong rạp đến từ màn ảnh khổng lồ, quang ảnh biến ảo chiếu lên những đường nét thưa thớt của khán giả. Biển báo lối thoát hiểm màu xanh phát ra ánh sáng yếu ớt.", "Loa vòm khổng lồ lấp đầy bởi tiếng nổ và nhạc phim, che phủ hoàn toàn các âm thanh nhỏ khác trong rạp.", "Không khí trôi nổi mùi bắp rang bơ, nước ngọt và chất tẩy rửa thảm, mọi người đều ẩn mình trong bóng tối, ánh mắt tập trung phía trước."],
        'Thang_máy': ["Vách trong bằng inox phản chiếu bóng người biến dạng, đèn trần là màu trắng lạnh lẽo, chiếu sáng mọi khuôn mặt mệt mỏi hoặc thờơ.", "Không gian bị lấp đầy hoàn toàn, cơ thể dán chặt vào cơ thể người khác, không thể di chuyển. Mùi nước hoa, mồ hôi trộn lẫn vào nhau.", "Cảm giác mất trọng lượng nhẹ khi thang máy vận hành, kèm theo sự nhảy số của đèn tầng, im lặng là ngôn ngữ duy nhất."],
        'default': ["Không khí có chút tinh vi, những người xung quanh đều đắm chìm trong thế giới riêng, không ai lưu ý việc đang xảy ra trong góc.", "Sự ồn ào của môi trường trở thành một lớp vỏ bọc, hòa tan mọi sự chạm khẽ và nhịp tim bí mật vào tiếng ồn nền.", "Ánh mắt giao nhau rồi vội vàng dời đi. Trong không gian công cộng này, mỗi người đều duy trì khoảng cách xã hội mong manh và vẻ mặt lạnh lùng."]
    };
    function getAtmosphere(sceneName) {
        if (!sceneName || sceneName === 'Không' || sceneName.includes('Đợi')) return '...';
        const key = Object.keys(atmospherePool).find(k => sceneName.includes(k));
        const pool = atmospherePool[key] || atmospherePool['default'];
        return _.sample(pool);
