    /* Độc thoại nội tâm */
    const innerThoughtsPool = {
        endurance_low: ["（Không... đừng mà... ai đó... cứu tôi với... cơ thể... thật kỳ lạ... không xong rồi... không thể chịu nổi nữa...）","（Ai cũng được... mau tới ngăn hắn lại... cơ thể mình... không nghe lời nữa rồi... sẽ hỏng mất...）","（Ý thức... thật mơ hồ... thật khó chịu... lại thật kỳ lạ... đây chính là... giới hạn rồi sao...?）"],
