        mid_conflict: ["（Tại sao... tại sao không phản kháng được... cơ thể trở nên thật nóng... thật kỳ lạ... đáng ghét... cảm giác... có chút thoải mái là sao chứ...）","（Lý trí đang bảo mình mau chạy đi... nhưng cơ thể lại đang mong đợi... mình rốt cuộc bị làm sao vậy... thật xấu hổ...）","（Cảm giác tội lỗi này... vừa sợ hãi vừa hưng phấn... không được... không thể tiếp tục thế này... nhưng mà...）"],
        endurance_shaken: ["（Dừng lại... mau dừng lại đi...! Cứ tiếp tục thế này... sẽ bị phát hiện mất...! Phải... phải nghĩ cách rời đi thôi...!）","（Cơ thể đang run rẩy... thật sợ hãi... cầu xin anh... đừng tiếp tục nữa...）","（Hơi thở thật khó khăn... tim đập nhanh quá... hắn rốt cuộc muốn làm gì...?）"],
        arousal_rising: ["（Đây là... cảm giác gì vậy...? Sâu trong cơ thể thật ngứa ngáy... dường như có thứ gì đó sắp trào ra... không được... phải nhịn lại...）","（Nóng quá... sâu trong bụng dưới có một luồng nhiệt... chuyện này là sao... cảm giác thật kỳ lạ...）","（Không được phát ra tiếng... tuyệt đối không được... nhưng mà... cơ thể... phản ứng của cơ thể... không lừa dối được ai...）"],
        initial_doubt: ["（Chuyện gì vậy...? Là ảo giác sao...? Luôn cảm thấy có người đang... không, không thể nào, chắc chắn là do mệt quá thôi.）","（Là tàu điện đang rung sao...? Hình như có thứ gì đó chạm vào... chắc chỉ là do đông người quá thôi...）","（Lạ thật... tại sao phía sau lại cảm thấy ngứa ngáy... đừng nghĩ lung tung nữa...）"]
    };
    function getInnerThoughts(endurance, arousal) {
        if (endurance < 40) return _.sample(innerThoughtsPool.endurance_low);
        if (arousal > 70) return _.sample(innerThoughtsPool.arousal_high);
        if (endurance < 70 && arousal > 40) return _.sample(innerThoughtsPool.mid_conflict);
        if (endurance < 70) return _.sample(innerThoughtsPool.endurance_shaken);
        if (arousal > 40) return _.sample(innerThoughtsPool.arousal_rising);
        return _.sample(innerThoughtsPool.initial_doubt);
    }

    function getExpressionDesc(endurance, arousal) {
        if (endurance < 30 || arousal > 70) return "Đôi má cô ấy ửng hồng bất thường, khóe mắt ẩm ướt, đôi môi khẽ mở, vô thức rò rỉ những tiếng thở dốc vụn vặt.";
        if (endurance < 60) return "Cô ấy cắn chặt môi dưới, đôi mày nhíu chặt, ánh mắt né tránh, dốc sức giả vờ như không có chuyện gì, nhưng cơ thể hơi run rẩy đã phản bội cô ấy.";
        return "Biểu cảm của cô ấy bình tĩnh và xa cách, ánh mắt trống rỗng, dường như đang đắm chìm trong suy nghĩ riêng, hoàn toàn không hay biết về những thay đổi xung quanh.";
    }

    function populateCharacterData() {
        const all_variables = getAllVariables();
        const data = _.get(all_variables, 'stat_data');

        if (!data || _.isEmpty(data) || _.get(data, 'Kẻ_biến_thái_hiện_tại.Bối_cảnh', 'Không') === 'Không') {
            $('#scene-name').text('Chờ trò chơi bắt đầu...');
            $('#atmosphere').text('...');
            $('#game-progress').text('Lượt: 0 / Thời gian còn lại: ...');
            $('#game-status').text('Trạng thái: Chờ');
            $('#target-name').text('Chờ nhân vật khởi tạo...');
            $('#scene-tags, #target-tags, #clothing-status-grid, #sensitivity-grid').html('');
            $('#target-expression').text('Biểu cảm của mục tiêu ẩn trong đám đông, không thể nhìn rõ.');
            $('#inner-thoughts').text('（...）');
            return;
        }

        const chikanData = _.get(data, 'Kẻ_biến_thái_hiện_tại', {});
        const characterPool = _.get(data, 'Dữ_liệu_nhân_vật', {});
        const targetName = _.get(chikanData, 'Nhân_vật_mục_tiêu', null);

        /* Thông tin bối cảnh trên cùng */
        const sceneName = _.get(chikanData, 'Bối_cảnh', 'Bối cảnh chưa rõ');
        const persistentTags = _.get(chikanData, 'Tag_duy_trì', []);
        const temporaryTags = Object.keys(_.get(chikanData, 'Tag_tạm_thời', {}));
        const allSceneTags = [...persistentTags, ...temporaryTags];
        const roundCount = _.get(chikanData, 'Số_lượt', 0);
        const remainingTime = _.get(chikanData, 'Thời_gian_còn_lại', 0);

        $('#scene-name').text(sceneName.replace(/_/g, ' '));
        $('#atmosphere').text(getAtmosphere(sceneName));
        $('#scene-tags').html(allSceneTags.map(tag => `<span class="tag">${(tag.split(':')[1] || tag).trim().replace(/_/g, ' ')}</span>`).join(''));
        $('#game-progress').text(`Lượt: ${roundCount} / Thời gian còn lại: ${remainingTime}m`);
        $('#game-status').text(`Trạng thái: ${_.get(chikanData, 'Trạng_thái', 'Đang_diễn_ra').replace(/_/g, ' ')}`);

        /* Thanh trạng thái bên trái */
        const vigilance = _.get(chikanData, 'Độ_cảnh_giác', 0);
        const endurance = _.get(chikanData, 'Độ_nhẫn_nhịn', 100);
        const arousal = _.get(chikanData, 'Độ_phát_tình', 0);

        $('#vigilance-bar .stat-bar-fill').css({'height': `${vigilance}%`, 'background-color': getVigilanceColor(vigilance)});
        $('#vigilance-value').text(`${vigilance} / 100`);
        $('#vigilance-desc').text(getVigilanceDesc(vigilance).replace(/_/g, ' '));

        $('#endurance-bar .stat-bar-fill').css({'height': `${endurance}%`, 'background-color': getEnduranceColor(endurance)});
        $('#endurance-value').text(`${endurance} / 100`);
        $('#endurance-desc').text(getEnduranceDesc(endurance).replace(/_/g, ' '));

        $('#arousal-bar .stat-bar-fill').css({'height': `${arousal}%`, 'background-color': getArousalColor(arousal)});
        $('#arousal-value').text(`${arousal} / 100`);
        $('#arousal-desc').text(getArousalDesc(arousal).replace(/_/g, ' '));

        /* Thông tin mục tiêu bên phải */
        if (targetName && characterPool[targetName]) {
            const characterData = characterPool[targetName];
            const charTags = _.get(chikanData, 'Tag_nhân_vật', []);

            $('#target-name').text(targetName.replace(/_/g, ' '));
            $('#target-tags').html(charTags.map(tag => `<span class="tag">${(tag.split(':')[1] || tag).trim().replace(/_/g, ' ')}</span>`).join(''));
            $('#target-expression').text(getExpressionDesc(endurance, arousal));

            const clothingStatus = _.get(chikanData, 'Trạng_thái_quần_áo', {});
            const clothingHtml = Object.entries(clothingStatus).map(([part, status]) => {
                return `<div class="clothing-item"><strong>${part.replace(/_/g, ' ')}:</strong> ${status.replace(/_/g, ' ')}<div class="clothing-desc">${getClothingDesc(status)}</div></div>`;
            }).join('');
            $('#clothing-status-grid').html(clothingHtml);

            $('#inner-thoughts').text(getInnerThoughts(endurance, arousal));

            const sensitivity = _.get(characterData, 'Bộ_phận', {});
            const sensitivityHtml = Object.entries(sensitivity).map(([part, data]) => {
                const level = data.Cấp_độ_nhạy_cảm || 1;
                const experience = data.Kinh_nghiệm || 0;
                return `<div class="sensitivity-item"><strong>${part.replace(/_/g, ' ')}:</strong> lv${level} / ${experience}xp</div>`;
            }).join('');
            $('#sensitivity-grid').html(sensitivityHtml);
        } else {
            $('#target-name').text('Chờ nhân vật khởi tạo...');
            $('#target-tags, #clothing-status-grid, #sensitivity-grid').html('');
            $('#target-expression').text('Biểu cảm của mục tiêu ẩn trong đám đông, không thể nhìn rõ.');
            $('#inner-thoughts').text('（...）');
        }
    }

    async function init() {
      await waitGlobalInitialized('Mvu');
      populateCharacterData();
      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, () => { populateCharacterData(); });
    }

    $(errorCatched(init));
  </script>
</head>
